	const std::string levelDataPath = "data/level/";

	const auto read_list = [](const YAML::Node& node, std::string_view nodeName, auto& list) {
		if (node[nodeName.data()] && node[nodeName.data()].IsSequence()) {
			for (const auto& child : node[nodeName.data()]) {
				decltype(auto) data = list.emplace_back();
				data.Read(child);
			}
		}
	};

	const auto read_vec3 = [](const YAML::Node& node) {
		glm::vec3 data;
		data.x = node["x"].as<float>(0.0f);
		data.y = node["y"].as<float>(0.0f);
		data.z = node["z"].as<float>(0.0f);
		return data;
	};

	// TriggerVolumeEvents
	void TriggerVolumeEvents::Read(const YAML::Node& node) {
		mOnEnter = node["onEnterEvent"].as<std::string>("");
		mOnExit = node["onExitEvent"].as<std::string>("");
	}

	// TriggerVolumeData
	void TriggerVolumeData::Read(const YAML::Node& node) {
		mShape = static_cast<TriggerVolumeShape>(node["shape"].as<uint32_t>(0));
		mActivationType = static_cast<TriggerVolumeActivationType>(node["triggerActivationType"].as<uint32_t>(0));

		if (node["offset"]) {
			mOffset = read_vec3(node["offset"]);
		}

		mOnEnter = node["onEnter"].as<std::string>("");
		mOnExit = node["onExit"].as<std::string>("");
		mOnStay = node["onStay"].as<std::string>("");
		mLuaCallbackOnEnter = node["luaCallbackOnEnter"].as<std::string>("");
		mLuaCallbackOnExit = node["luaCallbackOnExit"].as<std::string>("");
		mLuaCallbackOnStay = node["luaCallbackOnStay"].as<std::string>("");

		mTimeToActivate = node["timeToActivate"].as<float>(0.0f);

		mUseObjectDimensions = node["useGameObjectDimensions"].as<bool>(false);
		mIsKinematic = node["isKinematic"].as<bool>(false);
		mPersistentTimer = node["persistentTimer"].as<bool>(false);
		mTriggerOnceOnly = node["triggerOnceOnly"].as<bool>(false);
		mTriggerIfNotBeaten = node["triggerIfNotBeaten"].as<bool>(false);

		switch (mShape) {
			case TriggerVolumeShape::Sphere:
				mBoundingBox.extent = glm::vec3(node["sphereRadius"].as<float>(1.0f));
				break;

			case TriggerVolumeShape::Box:
				mBoundingBox.extent = glm::vec3(
					node["boxWidth"].as<float>(1.0f),
					node["boxHeight"].as<float>(1.0f),
					node["boxLength"].as<float>(1.0f)
				);
				break;

			case TriggerVolumeShape::Capsule:
				auto radius = node["capsuleRadius"].as<float>(1.0f);
				mBoundingBox.extent = glm::vec3(radius, node["capsuleHeight"].as<float>(1.0f), radius);
				break;
		}

		if (node["events"]) {
			mEvents.Read(node["events"]);
		}
	}

