	// Level
	Level::Level() {

	}

	Level::~Level() {

	}

	bool Level::Load(const std::string& difficultyName, const std::string& levelName) {
		const std::string fullPath = levelDataPath + difficultyName + "/" + levelName + ".level.yaml";
		if (!std::filesystem::exists(fullPath)) {
			std::cout << "Level: Could not find '" << fullPath << "'." << std::endl;
			return false;
		}

		try {
			YAML::Node document = YAML::LoadFile(fullPath);
			if (!document["level"]) {
				return false;
			}

			const auto& node = document["level"];

			if (node["markersets"] && node["markersets"].IsSequence()) {
				for (const auto& child : node["markersets"]) {
					const auto markersetAsset = child["markersetAsset"].as<std::string>("");
					if (markersetAsset.empty()) {
						continue;
					}

					const auto& [it, added] = mMarkersets.try_emplace(utils::hash_id(markersetAsset));
					if (added) {
						it->second.mName = markersetAsset;
						it->second.Load(difficultyName + "/" + markersetAsset + ".yaml");
					}
				}
			}

			if (node["levelConfig"]) {
				mConfig.Read(node["levelConfig"]);
			}
			if (node["firstTimeConfig"]) {
				mFirstTimeConfig.Read(node["firstTimeConfig"]);
			}

			const auto planetConfigName = node["planetConfig"].as<std::string>("");
			if (!planetConfigName.empty()) {
				// mPlanetConfig.Read(open_the_file);
			}

			return true;
		} catch (const YAML::Exception& e) {
			std::cout << "Level: Could not load '" << fullPath << "': " << e.what() << std::endl;
		}
		return false;
	}

	bool Level::GetMarkerset(const std::string& name, Markerset& markerset) const {
		if (auto it = mMarkersets.find(utils::hash_id(name)); it != mMarkersets.end()) {
			markerset = it->second;
			return true;
		}
		return false;
	}

